)
from logger import get_logger

logger = get_logger(__name__)


class ConfigurationError(Exception):
    """Raised when configuration is invalid or missing."""
    pass


class Config:
    """Configuration manager for the URL shortener service."""

    def __init__(self, config_path: Optional[str] = None):
        """
        Initialize configuration from file or defaults.

        Args:
            config_path: Path to configuration file (YAML)
        """
        self.config_path = config_path or DEFAULT_CONFIG_PATH
        self._config: Dict[str, Any] = {}
        self._load_config()
        self._validate_config()

    def _load_config(self) -> None:
        """Load configuration from YAML file with defaults."""
        # Set defaults
        self._config = {
            "service": {
                "host": DEFAULT_HOST,
                "port": DEFAULT_PORT,
                "cache_size": DEFAULT_CACHE_SIZE,
                "cache_ttl": DEFAULT_CACHE_TTL,
            },
            "http_client": {
                "timeout": DEFAULT_TIMEOUT,
                "max_retries": MAX_RETRIES,
                "verify_ssl": True,
            },
            "logging": {
                "level": DEFAULT_LOG_LEVEL,
                "file": None,
            },
        }

        # Try to load from file
        config_file = Path(self.config_path)
        if config_file.exists():
            try:
                with open(config_file, 'r') as f:
                    file_config = yaml.safe_load(f) or {}
                    self._merge_config(self._config, file_config)
                logger.info(f"Configuration loaded from {self.config_path}")
            except yaml.YAMLError as e:
                raise ConfigurationError(f"Invalid YAML in config file: {e}")
            except Exception as e:
                raise ConfigurationError(f"Error reading config file: {e}")
        else:
            logger.warning(
                f"Config file {self.config_path} not found, using defaults"
            )

        # Override with environment variables
        self._load_env_overrides()

    def _merge_config(self, base: Dict, override: Dict) -> None:
        """
        Recursively merge override config into base config.

        Args:
            base: Base configuration dictionary
            override: Override configuration dictionary
        """
        for key, value in override.items():
            if key in base and isinstance(base[key], dict) and isinstance(value, dict):
                self._merge_config(base[key], value)
            else:
                base[key] = value

    def _load_env_overrides(self) -> None:
        """Load configuration overrides from environment variables."""
        env_mappings = {
            "SERVICE_HOST": ("service", "host"),
            "SERVICE_PORT": ("service", "port", int),
            "HTTP_TIMEOUT": ("http_client", "timeout", int),
            "HTTP_MAX_RETRIES": ("http_client", "max_retries", int),
            "LOG_LEVEL": ("logging", "level"),
            "LOG_FILE": ("logging", "file"),
        }

        for env_var, mapping in env_mappings.items():
            value = os.getenv(env_var)
            if value is not None:
                section = mapping[0]
                key = mapping[1]
                converter = mapping[2] if len(mapping) > 2 else str

                try:
                    self._config[section][key] = converter(value)
                    logger.debug(f"Override from env: {env_var}={value}")
                except (ValueError, KeyError) as e:
                    logger.warning(f"Invalid env override {env_var}: {e}")

    def _validate_config(self) -> None:
        """Validate configuration values."""
        # Validate port
        port = self.get("service", "port")
        if not isinstance(port, int) or port < 1 or port > 65535:
            raise ConfigurationError(f"Invalid port: {port}")

        # Validate timeout
        timeout = self.get("http_client", "timeout")
        if not isinstance(timeout, (int, float)) or timeout <= 0:
            raise ConfigurationError(f"Invalid timeout: {timeout}")

        # Validate max_retries
        max_retries = self.get("http_client", "max_retries")
        if not isinstance(max_retries, int) or max_retries < 0:
            raise ConfigurationError(f"Invalid max_retries: {max_retries}")

        # Validate log level
        valid_levels = ["DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"]
        log_level = self.get("logging", "level").upper()
        if log_level not in valid_levels:
            raise ConfigurationError(f"Invalid log level: {log_level}")

        logger.info("Configuration validated successfully")

    def get(self, section: str, key: str, default: Any = None) -> Any:
        """
        Get configuration value by section and key.

        Args:
            section: Configuration section
            key: Configuration key
            default: Default value if not found

        Returns:
            Configuration value or default
        """
        return self._config.get(section, {}).get(key, default)

    def get_section(self, section: str) -> Dict[str, Any]:
        """
        Get entire configuration section.

        Args:
            section: Configuration section name

        Returns:
            Dictionary with section configuration
        """
        return self._config.get(section, {})

    def to_dict(self) -> Dict[str, Any]:
        """Return full configuration as dictionary."""
        return self._config.copy()

    def __repr__(self) -> str:
        """String representation of configuration."""
        return f"Config(path={self.config_path}, sections={list(self._config.keys())})"
